SELECT "febos" AS azienda, [Cust_ Ledger Entry].[Entry No_], [Cust_ Ledger Entry].[Customer No_], [Cust_ Ledger Entry].[Posting Date], [Cust_ Ledger Entry].[Document Type], [Cust_ Ledger Entry].[Document No_], [Cust_ Ledger Entry].Description, [0-NEWERA-PARTITECLIENTI-STEP0].importo AS Amount, [Cust_ Ledger Entry].[Salesperson Code], [Cust_ Ledger Entry].[Due Date], [Cust_ Ledger Entry].[Document Date], [Cust_ Ledger Entry].[External Document No_], [Cust_ Ledger Entry].[Payment Method code], [Cust_ Ledger Entry].[Bank Receipt], [Cust_ Ledger Entry].[Document Occurrence], [Cust_ Ledger Entry].Note, [Cust_ Ledger Entry].[Letter No_], [Cust_ Ledger Entry].[Bank Account No_], [Cust_ Ledger Entry].[Customer Bill No_], [Cust_ Ledger Entry].[Bank Receipts List No_], Dimensioni_NE.CCR, Dimensioni_NE.MARCHIO, Dimensioni_NE.STAGIONE, Dimensioni_NE.LINEA
FROM ([0-NEWERA-PARTITECLIENTI-STEP0] INNER JOIN [Cust_ Ledger Entry] ON [0-NEWERA-PARTITECLIENTI-STEP0].[Cust_ Ledger Entry No_] = [Cust_ Ledger Entry].[Entry No_]) LEFT JOIN Dimensioni_NE ON [Cust_ Ledger Entry].[Dimension Set ID] = Dimensioni_NE.[Dimension Set ID];

